class Solution {
    int ans=0;
    int dfs(TreeNode* n){
        if(!n) return 0;
        int l=dfs(n->left), r=dfs(n->right), ll=0, rr=0;
        if(n->left&&n->left->val==n->val) ll=l+1;
        if(n->right&&n->right->val==n->val) rr=r+1;
        ans=max(ans,ll+rr); return max(ll,rr);
    }
public:
    int longestUnivaluePath(TreeNode* root){ dfs(root); return ans; }
};
